class GameServer:
    def __init__(self, host: str, port: int, tick_rate: int):
        self.host = host
        self.port = port
        self.tick_rate = tick_rate
        self.players: Dict[int, PlayerState] = {}
        self.writers: Dict[int, asyncio.StreamWriter] = {}
        self.reader_tasks: Dict[int, asyncio.Task] = {}
        self.next_pid = 1
        self.running = True
